import React, { useRef, useEffect } from 'react';
import { Col } from 'react-bootstrap';

const Parallax = ({ scrollPercentage, parallaxImages }) => {
  const imageRefs = useRef([]);

  useEffect(() => {
    const handleScroll = () => {
      imageRefs.current.forEach((el, index) => {
        const { imgSpeed, imgOffsetX } = parallaxImages[index];
        const xPos = (scrollPercentage * imgSpeed) + imgOffsetX;
        el.style.transform = `translateX(${xPos}px)`;
      });
    };

    window.addEventListener('scroll', handleScroll);
    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, [scrollPercentage]);

  // Ajustar el offset inicial para cada imagen
  useEffect(() => {
    imageRefs.current.forEach((el, index) => {
      const { imgOffsetX } = parallaxImages[index];
      const xPos = imgOffsetX;
      el.style.transform = `translateX(${xPos}px)`;
    });
  }, []);

  return (
    <div style={{ position: 'relative', overflow: 'hidden', height: '100vh' }}>
      {parallaxImages.map((image, index) => (
        <Col
          key={index}
          className={`position-absolute top-0 start-0 layer${index}`}
          ref={el => imageRefs.current[index] = el}
          style={{ zIndex: index, backgroundImage: `url(${image.imgSrc})`, backgroundRepeat: 'repeat-x' }}
        />
      ))}
    </div>
  );
};

export default Parallax;
